// Phase 6.5: refresh devdriver.html (accurate driver list + comparison + printer/PDF
// parity) and document the "Recalculate report" Printer Fonts option in pagesetup.html.
import fs from 'node:fs';
import path from 'node:path';
const ROOT = path.resolve(import.meta.dirname, '..', '..');

const DEV_TITLE = 'Driver architecture of Report Manager';
const DEV_BODY = `<h2>Developer</h2>
<h3>Driver architecture of Report Manager</h3>
<p>Report Manager is a <b>driver-based</b> engine. A report is laid out once into a
  device-independent <b>metafile</b>, and a render driver then paints that metafile to a
  particular target. Any object that implements the <code>IRpPrintDriver</code> interface
  (declared in <code>rpmetafile.pas</code>) can act as a driver.</p>
<p>The drivers included with Report Manager are:</p>
<table border="1">
  <tr><th>Output</th><th>Unit</th><th>Platform</th><th>Notes</th></tr>
  <tr><td>PDF</td><td>rppdfdriver</td><td>Windows / Linux</td><td>Fixed 72&nbsp;dpi layout, embedded/subset fonts and complex-script shaping; no graphical-environment dependency, so it runs headless on a server.</td></tr>
  <tr><td>SVG</td><td>rpsvgdriver</td><td>Windows / Linux</td><td>Scalable vector output for the web.</td></tr>
  <tr><td>HTML</td><td>rphtmldriver</td><td>Windows / Linux</td><td>HTML export of the report pages.</td></tr>
  <tr><td>Windows GDI (preview and printer)</td><td>rpgdidriver</td><td>Windows</td><td>The preview window and direct printing; uses DirectWrite for text shaping.</td></tr>
  <tr><td>Plain text</td><td>rptextdriver</td><td>Windows / Linux</td><td>Text output, useful for dot-matrix and POS printers.</td></tr>
  <tr><td>CSV</td><td>rpcsvdriver</td><td>Windows / Linux</td><td>Comma-separated values for import into spreadsheets.</td></tr>
  <tr><td>Metafile</td><td>rpmetafile</td><td>Windows / Linux</td><td>The native, device-independent page format; can be re-rendered later by any other driver.</td></tr>
</table>
<p>Lazarus/FPC builds add an LCL driver (<code>rplcldriver</code>) for preview and printing,
  and the .NET / .NET&nbsp;Core libraries provide their own rendering. The legacy Kylix/Qt
  driver (<code>rpqtdriver</code>) and the Windows-only Excel export (<code>rpexceldriver</code>)
  are kept only for backward compatibility.</p>
<p>The <b>Web Report Server</b> and the <b>TCP Report Server</b> always render with the PDF
  driver, which has no dependency on a graphical environment and therefore runs as a console
  service on Linux.</p>

<h3>How a driver is used</h3>
<p>While calculating the report the engine asks the driver for text and graphic sizes; once
  the layout (the metafile) has been computed, the same driver &ndash; or a different one
  &ndash; paints each page. Because the metafile is device-independent, a report can be
  calculated with one driver and printed with another: a metafile generated by the web
  server, for example, can be printed later with metaviewxp on Windows or metaview on Linux.</p>
<p>The size queries are:</p>
<p><code>procedure TextExtent(atext:TRpTextObject; var extent:TPoint); stdcall;</code><br>
<code>procedure GraphicExtent(Stream:TMemoryStream; var extent:TPoint; dpi:integer); stdcall;</code></p>
<p>The engine uses them to reserve space for auto-expanding and auto-contracting sections
  and components.</p>

<h3>Choosing an output driver</h3>
<p>Every driver paints the same metafile, so the page geometry is identical; the drivers
  differ in fidelity and in their intended use:</p>
<ul>
  <li><b>PDF</b> &ndash; the most faithful portable output and the recommended format for
    archiving, e-mail and the report servers; it works at a fixed resolution, so it looks
    the same in every viewer.</li>
  <li><b>Windows GDI</b> &ndash; on-screen preview and direct printing on Windows.</li>
  <li><b>SVG / HTML</b> &ndash; for embedding the report in web pages.</li>
  <li><b>Plain text / CSV</b> &ndash; data-oriented output (dot-matrix, POS, import into a
    spreadsheet); fonts, colors and graphics are not preserved.</li>
  <li><b>Metafile</b> &ndash; store the report once and render it later to any of the above.</li>
</ul>

<h3>Matching printer and PDF output</h3>
<p>Text can be measured with the screen canvas or with the target printer. Screen and printer
  resolutions differ and a font may be drawn slightly differently on each, so the preview,
  GDI printing and PDF output could previously show small differences in text width.</p>
<p>The <b>Printer Fonts</b> option in <a href="pagesetup.html">page setup</a> now offers a
  <b>Recalculate report</b> mode that recomputes the layout using the target device metrics
  (a glyph-exact pipeline). With it the <b>printer and PDF output are practically
  identical</b>. Metafiles produced this way are stored in format&nbsp;4.1 and keep the
  glyph-exact information, so they print the same when re-rendered later. The PDF driver
  already knows exact font sizes and works at a fixed 72&nbsp;dpi resolution, so PDF is
  consistent across viewers.</p>`;

const PAGESETUP_FONTS = `<p><b>Printer Fonts property</b> controls how the engine measures text. It has four options:</p>
<table border="1">
  <tr><th>Option</th><th>Meaning</th></tr>
  <tr><td>Default</td><td>Use the engine's default behaviour.</td></tr>
  <tr><td>Always use printer fonts</td><td>On Microsoft Windows, use the native printer fonts (for example on dot-matrix printers) for the best precision and speed; the correct driver for the selected printer, or for the printer it emulates, must be installed.</td></tr>
  <tr><td>Never use printer fonts</td><td>Never substitute printer fonts; always measure with the standard font metrics.</td></tr>
  <tr><td>Recalculate report</td><td>Recompute the report layout using the target device font metrics (a glyph-exact pipeline). This makes the <b>printer and PDF output practically identical</b>; the report metafile is stored in format 4.1 so it keeps this fidelity when re-rendered later. See <a href="devdriver.html">driver architecture</a> for details.</td></tr>
</table>`;

// devdriver.html: replace the whole <main> with a fresh h1 + body.
{
  const f = path.join(ROOT, 'doc/doc/devdriver.html');
  let html = fs.readFileSync(f, 'utf8');
  const m = html.match(/<main class="doc-main">[\s\S]*?<\/main>/i);
  html = html.replace(m[0], `<main class="doc-main">\n<h1>${DEV_TITLE}</h1>\n${DEV_BODY}\n</main>`);
  fs.writeFileSync(f, html, 'utf8');
  console.log('rewrote devdriver.html');
}

// pagesetup.html: replace the single "Printer Fonts property" paragraph with the table.
{
  const f = path.join(ROOT, 'doc/doc/pagesetup.html');
  let html = fs.readFileSync(f, 'utf8');
  const re = /<p><b>Printer Fonts property<\/b>[\s\S]*?<\/p>/i;
  if (!re.test(html)) { console.error('pagesetup: Printer Fonts paragraph not found'); process.exit(1); }
  html = html.replace(re, PAGESETUP_FONTS);
  fs.writeFileSync(f, html, 'utf8');
  console.log('updated pagesetup.html Printer Fonts section');
}
